  setCanvasPexels(setMarco=1) {

    if(setMarco==1){
      this.setMarco();
    }    

    const canvasEl: HTMLCanvasElement = this.canvas.nativeElement;
    const ctx = canvasEl.getContext('2d');

    const img1 = new Image();
    img1.crossOrigin = 'Anonymous';
    //img1.crossOrigin = '';

    img1.src = this.pexelsUrl;
    img1.onload = () => {

      // img1.width = 512;
      // img1.height = 512;

      canvasEl.width = img1.width;
      canvasEl.height = img1.height;

      ctx.drawImage(img1, 0, 0);

      if(this.marcoUrl){
        const img2 = new Image();
        img2.crossOrigin = 'Anonymous';
        img2.src = this.marcoUrl;
        img2.onload = () => {
          ctx.drawImage(img2, 0, 0, img1.width, img1.height);

          // Convertir el canvas en una imagen y mostrarla en la página
          //var img = canvasEl.toDataURL("image/png");
          var img = canvasEl.toDataURL("image/jpeg");
          this.imgPostBase64 = img;

        };  
      }else{
        // Convertir el canvas en una imagen y mostrarla en la página
        //var img = canvasEl.toDataURL("image/png");
        var img = canvasEl.toDataURL("image/jpeg");
        this.imgPostBase64 = img;
      }

    };
  }

