  downloadImageFromBase64(base64Data, filename) {
    var element = document.createElement('a');
    //element.setAttribute('href', 'data:image/png;base64,' + base64Data);
    element.setAttribute('href', base64Data);
    element.setAttribute('download', filename);
    element.style.display = 'none';
    document.body.appendChild(element);
    element.click();
    document.body.removeChild(element);
  }

  fixBinary (bin) {
    var length = bin.length;
    var buf = new ArrayBuffer(length);
    var arr = new Uint8Array(buf);
    for (var i = 0; i < length; i++) {
      arr[i] = bin.charCodeAt(i);
    }
    return buf;
  }

  subirArchivo(){

    this.loading = true;

    var jpg = this.imgPostBase64.split(',')[1];
    var binary = this.fixBinary(window.atob(jpg));// <-- Usamos la fn "fixBinary"
    var the_file = new Blob([binary], {type: 'image/jpeg'});// <-- Sacamos el encode
    var imagen_firma = new File([the_file], 'imagen_firma.jpeg', { type: 'image/jpeg' });

    //Crear el objeto FormData y agregar la imagen 
    const formData = new FormData();
    formData.append('archivo', imagen_firma);

    var that = this;

    this.api_serv.postQueryUpload('posts/binario/to/url', formData)
    .subscribe({
      next(data : any) {
        console.log(data);
        that.loading = false;
      },
      error(msg) {
        console.log(msg);
        that.loading = false;
        that.tratarError(msg);
      }
    });

  }

