  initAllCanvas(){

    //ordenar array de imagenes de forma aleatorea
    this.imagenes.sort(this.compareRandom);

    if(this.selectImgIndex === null && this.imagenes.length > 0){
      this.selectImgIndex = 0;
      if(this.imagenes[this.selectImgIndex].proveedor == 'pexels'){
        this.pexelsUrl = this.imagenes[this.selectImgIndex].src;
        this.setCanvasPexels();
      }else if(this.imagenes[this.selectImgIndex].proveedor == 'cliente'){
        this.clienteImageUrl = this.imagenes[this.selectImgIndex].imagen_url;
        this.setCanvasCliente();
      }else if(this.imagenes[this.selectImgIndex].proveedor == 'dalle'){
        //this.dalleBase64 = 'data:image/png;base64,'+this.imagenes[this.selectImgIndex].b64_json;
        this.dalleBase64 = 'data:image/jpeg;base64,'+this.imagenes[this.selectImgIndex].b64_json;
        this.setCanvas();
      }
    } 

  }

